UPDATE lessons SET content = 'Для управления своими заказами и аккаунтом, перейдите в личный кабинет, нажав на иконку профиля «我的» в правом нижнем углу экрана. ID аккаунта находится в верхнем левом углу, правее от аватара.

Основные разделы личного кабинета: (1) — Настроить кабинет. (2) — Товары, которые ожидают платежа (待付款). (3) — Товары, которые ожидают отправки (待发货). (4) — Заказы. (5) — Полученные заказы (待收货). (6) — Возврат товара (退款/售后). (7) — Вкладка с магазинами, на которые вы подписаны (关注店铺). (8) — Избранные товары (收藏). (9) — История просмотра товаров (足迹). (10) — Купоны на скидку (红包卡券). (11) — Купить сейчас, оплатить потом (先采后付). (12) — Переключение учётной записи (分销管理). (13) — Управление адресами доставки (收货地址). (14) — Завод (元宝工厂). (15) — Поддержка (官方客服). (16) — Мой курьер (我的快递).' WHERE id = '84af60ce-2085-4142-9f9f-9d74801dd0df';